La collecte de preuves en environnement Windows suit l'ordre de volatilité. PowerShell permet d'automatiser entièrement ce processus.

```powershell
# Triage rapide Windows — collecte des données volatiles

$incidentId = "INC-$(Get-Date -Format 'yyyyMMdd-HHmmss')"
$dir = "$env:TEMP\$incidentId"
New-Item -ItemType Directory -Path $dir | Out-Null

function Collect {
    param([string]$Nom, [scriptblock]$Commande)
    Write-Host "Collecte : $Nom"
    try {
        & $Commande | Out-File -FilePath "$dir\$Nom.txt" -Encoding UTF8
    } catch {
        "ERREUR : $_" | Out-File -FilePath "$dir\$Nom.txt" -Encoding UTF8
    }
}

# ─── Métadonnées ───
Collect 'metadata' { 
    [PSCustomObject]@{
        Timestamp  = Get-Date -Format 'o'
        Hostname   = $env:COMPUTERNAME
        Username   = $env:USERNAME
        Domain     = $env:USERDOMAIN
        OS         = (Get-WmiObject Win32_OperatingSystem).Caption
        Uptime     = (Get-Date) - (gcim Win32_OperatingSystem).LastBootUpTime
    } | Format-List
}

Write-Host "Dossier de collecte : $dir"
```

```powershell
$incidentId = "INC-$(Get-Date -Format 'yyyyMMdd-HHmmss')"
$dir = "$env:TEMP\$incidentId"
New-Item -ItemType Directory -Path $dir -Force | Out-Null

function Collect {
    param([string]$Nom, [scriptblock]$Commande)
    Write-Host "Collecte : $Nom"
    try { & $Commande | Out-File "$dir\$Nom.txt" -Encoding UTF8 }
    catch { "ERREUR : $_" | Out-File "$dir\$Nom.txt" -Encoding UTF8 }
}

# Processus actifs avec chemins
Collect 'processes' {
    Get-Process | Select-Object Id, Name, CPU, WorkingSet, Path, StartTime |
        Sort-Object CPU -Descending
}

# Connexions réseau avec processus
Collect 'netstat' {
    Get-NetTCPConnection -State Established -ErrorAction SilentlyContinue |
        Select-Object LocalAddress, LocalPort, RemoteAddress, RemotePort, State,
        @{N='Process';E={(Get-Process -Id $_.OwningProcess -EA SilentlyContinue).Name}} |
        Sort-Object RemoteAddress
}

# Services en cours d'exécution
Collect 'services' {
    Get-Service | Where-Object Status -eq 'Running' |
        Select-Object Name, DisplayName, Status, StartType
}

# Utilisateurs connectés
Collect 'users' {
    query user 2>&1
    Get-LocalUser | Select-Object Name, Enabled, LastLogon, PasswordLastSet
}

# Tâches planifiées
Collect 'scheduled_tasks' {
    Get-ScheduledTask | Where-Object State -ne 'Disabled' |
        Select-Object TaskName, TaskPath, State,
        @{N='LastRun';E={$_.LastRunTime}} | Sort-Object LastRun -Descending |
        Select-Object -First 50
}

Write-Host "`nCollecte terminée : $dir"
Get-ChildItem $dir | Select-Object Name, Length | Format-Table
```
